_U2:"precision mediump float;\n#define LOWPREC lowp\n// Uniforms look like they're shared between vertex and fragment shaders in GLSL, so we have to be careful to avoid name clashes\n\nuniform sampler2D gm_BaseTexture;\n\nuniform bool gm_PS_FogEnabled;\nuniform vec4 gm_FogColour;\nuniform bool gm_AlphaTestEnabled;\nuniform float gm_AlphaRefValue;\n\nvoid DoAlphaTest(vec4 SrcColour)\n{\n	if (gm_AlphaTestEnabled)\n	{\n		if (SrcColour.a <= gm_AlphaRefValue)\n		{\n			discard;\n		}\n	}\n}\n\nvoid DoFog(inout vec4 SrcColour, float fogval)\n{\n	if (gm_PS_FogEnabled)\n	{\n		SrcColour = mix(SrcColour, gm_FogColour, clamp(fogval, 0.0, 1.0)); \n	}\n}\n\n#define _YY_GLSLES_ 1\n//\n// Simple passthrough fragment shader\n//\nvarying vec2 v_vTexcoord;\nvarying vec4 v_vColour;\n\nuniform float u_time; // Controls the movement of the shimmer\n\nvoid main() {\n    // Get the original pixel color and transparency\n    vec4 base_color = v_vColour * texture2D(gm_BaseTexture, v_vTexcoord);\n    \n    // Create a diagonal line coordinate mapping\n    float line_pos = v_vTexcoord.x + v_vTexcoord.y;\n    \n    // Calculate the shimmer position using a moving sine wave\n    // Adjust 0.15 to change the width of the shimmer stripe\n    float shimmer = smoothstep(0.15, 0.0, abs(line_pos - u_time));\n    \n    // Add the white shimmer tint strictly to non-transparent pixels\n    // Adjust 0.5 to make the shimmer brighter or subtler\n    base_color.rgb += vec3(shimmer * 0.5) * base_color.a;\n    \n    gl_FragColor = base_color;\n}\n",
